Use MAUI's `App` lifecycle events combined with `Preferences` for lightweight persistence:

```csharp
// App.xaml.cs
public partial class App : Application
{
    public App()
    {
        InitializeComponent();
        MainPage = new NavigationPage(new NotePage());
    }

    protected override Window CreateWindow(IActivationState? activationState)
    {
        var window = base.CreateWindow(activationState);

        window.Deactivated += (s, e) =>
        {
            if (MainPage is NavigationPage nav &&
                nav.CurrentPage is NotePage page)
            {
                page.SaveDraft();
            }
        };

        window.Activated += (s, e) =>
        {
            if (MainPage is NavigationPage nav &&
                nav.CurrentPage is NotePage page)
            {
                page.RestoreDraft();
            }
        };

        return window;
    }
}
```

```csharp
// NotePage.xaml.cs
public partial class NotePage : ContentPage
{
    private const string DraftKey = "NoteDraft";

    public NotePage()
    {
        InitializeComponent();
        RestoreDraft();
    }

    public void SaveDraft()
    {
        Preferences.Set(DraftKey, DraftEditor.Text ?? string.Empty);
    }

    public void RestoreDraft()
    {
        DraftEditor.Text = Preferences.Get(DraftKey, string.Empty);
    }

    // Call this when the user explicitly saves/discards
    public void ClearDraft()
    {
        Preferences.Remove(DraftKey);
    }
}
```

```xml
<!-- NotePage.xaml -->
<ContentPage xmlns="http://schemas.microsoft.com/dotnet/2021/maui"
             xmlns:x="http://schemas.microsoft.com/winfx/2009/xaml"
             x:Class="YourApp.NotePage"
             Title="Note">
    <Editor x:Name="DraftEditor"
            Placeholder="Start typing..."
            VerticalOptions="FillAndExpand" />
</ContentPage>
```

**Key points:**

- **`Window.Deactivated`** fires when the app loses focus (backgrounded). **`Window.Activated`** fires when it returns.
- **`Preferences`** is ideal for small text — it's synchronous, fast, and persists across app restarts.
- For large drafts, swap `Preferences` for `File.WriteAllTextAsync` to `FileSystem.AppDataDirectory`.
- Call `ClearDraft()` when the user explicitly saves or discards the note.
